// Compute date windows in America/Los_Angeles. Body opts override.
// Yesterday rolls Fri->Mon: on Monday, 'yesterday' is Friday.
// Lookback window covers Sat/Sun on Mondays.

const body = (($input.first() || {}).json || {}).body || {};
const override = body.yesterday_date; // optional 'YYYY-MM-DD' for testing

// Get parts of 'now' in PT via Intl
function ptParts(d) {
  const fmt = new Intl.DateTimeFormat('en-CA', {
    timeZone: 'America/Los_Angeles',
    year: 'numeric', month: '2-digit', day: '2-digit',
    weekday: 'short', hour: '2-digit', minute: '2-digit',
    hour12: false,
  });
  const parts = Object.fromEntries(fmt.formatToParts(d).map(p => [p.type, p.value]));
  return parts;
}

const now = new Date();
const nowParts = ptParts(now);
const today_pt = `${nowParts.year}-${nowParts.month}-${nowParts.day}`;
const weekday = nowParts.weekday; // Mon, Tue, ...

function addDays(iso, n) {
  const d = new Date(iso + 'T12:00:00Z');
  d.setUTCDate(d.getUTCDate() + n);
  return d.toISOString().slice(0, 10);
}

let yesterday_pt;
let lookback_start_pt;
if (override) {
  yesterday_pt = override;
  lookback_start_pt = override;
} else if (weekday === 'Mon') {
  yesterday_pt = addDays(today_pt, -3); // Friday
  lookback_start_pt = addDays(today_pt, -3); // Friday (captures Fri/Sat/Sun)
} else {
  yesterday_pt = addDays(today_pt, -1);
  lookback_start_pt = addDays(today_pt, -1);
}

// Build long-form labels
const weekdayLong = new Intl.DateTimeFormat('en-US', {
  timeZone: 'America/Los_Angeles', weekday: 'long',
}).format(new Date(yesterday_pt + 'T12:00:00Z'));
const yesterdayLabel = new Intl.DateTimeFormat('en-US', {
  timeZone: 'America/Los_Angeles', month: 'long', day: 'numeric',
}).format(new Date(yesterday_pt + 'T12:00:00Z'));
const todayWeekdayLong = new Intl.DateTimeFormat('en-US', {
  timeZone: 'America/Los_Angeles', weekday: 'long',
}).format(new Date(today_pt + 'T12:00:00Z'));
const todayLabel = new Intl.DateTimeFormat('en-US', {
  timeZone: 'America/Los_Angeles', month: 'long', day: 'numeric',
}).format(new Date(today_pt + 'T12:00:00Z'));

// Calendar time bounds: lookback_start 00:00 PT to today 23:59 PT, expressed as RFC3339 with -07:00/-08:00 offset.
// We use -07:00 during PDT; PT is currently PDT through fall back. n8n cloud is UTC so we hardcode -07:00 here; if DST changes, edit to -08:00.
const cal_timeMin = `${lookback_start_pt}T00:00:00-07:00`;
const cal_timeMax = `${today_pt}T23:59:59-07:00`;

// Gmail search dates use YYYY/MM/DD
const gmail_after = lookback_start_pt.replace(/-/g, '/');
const gmail_before = addDays(today_pt, 1).replace(/-/g, '/');

return {
  today_pt,
  yesterday_pt,
  lookback_start_pt,
  weekday,
  yesterday_long: `${weekdayLong}, ${yesterdayLabel}`,
  today_long: `${todayWeekdayLong}, ${todayLabel}`,
  cal_timeMin,
  cal_timeMax,
  gmail_after,
  gmail_before,
};

// Assemble all source data into one payload + build the LLM prompt.

const dates = $('Compute dates').first().json;
const meetings = ($('Pull federated meetings').first() || {}).json || {};
const cal = ($('Pull Calendar').first() || {}).json || {};
const gmail = ($('Pull Gmail sent').first() || {}).json || {};
const slack = ($('Pull Slack from Sales User').first() || {}).json || {};
const openTasks = ($('Pull Open Tasks').first() || {}).json || {};

// --- Sanitize Meetings ---
function extractTitle(page) {
  const p = page.properties || {};
  for (const key of ['Name', 'Title', 'Meeting', 'Task']) {
    const prop = p[key];
    if (prop && prop.title) return prop.title.map(t => t.plain_text || '').join('').trim();
  }
  for (const k of Object.keys(p)) {
    if (p[k].title) return p[k].title.map(t => t.plain_text || '').join('').trim();
  }
  return '(untitled)';
}
function extractDate(page) {
  const p = page.properties || {};
  for (const key of ['Start Time', 'Date', 'Meeting Date', 'Created']) {
    if (p[key] && p[key].date && p[key].date.start) return p[key].date.start.slice(0, 10);
  }
  return null;
}
function slimMeeting(page) {
  return {
    title: extractTitle(page),
    date: extractDate(page),
    url: page.url,
  };
}
const paired = (meetings.pairs || []).map(p => ({
  type: 'paired',
  CRM: p.sample_company ? slimMeeting(p.sample_company) : null,
  recall: p.recall ? slimMeeting(p.recall) : null,
}));
const unpaired_CRM = (meetings.unpaired_sample_company || []).map(p => ({ type: 'CRM-only', ...slimMeeting(p) }));
const unpaired_recall = (meetings.unpaired_recall || []).map(p => ({ type: 'recall-only', ...slimMeeting(p) }));
const meetings_clean = {
  pairs: paired.slice(0, 20),
  CRM_only: unpaired_CRM.slice(0, 20),
  recall_only: unpaired_recall.slice(0, 20),
  counts: meetings.counts || {},
  error: meetings.error || null,
};

// --- Sanitize Calendar (filter declined + personal) ---
const personalPatterns = [/ballet/i, /school pickup/i, /pickup/i, /leave for/i, /dinner with/i, /family/i, /\bgym\b/i, /\bkid/i];
function isPersonal(s) { return personalPatterns.some(r => r.test(s || '')); }
const myEmail = 'sales.user@example.com';
const calItems = (cal.items || []).filter(ev => {
  const myAttendee = (ev.attendees || []).find(a => a.email === myEmail || a.self);
  if (myAttendee && myAttendee.responseStatus === 'declined') return false;
  if (ev.status === 'cancelled') return false;
  if (isPersonal(ev.summary)) return false;
  return true;
}).map(ev => ({
  title: ev.summary || '(no title)',
  start: (ev.start && (ev.start.dateTime || ev.start.date)) || null,
  end: (ev.end && (ev.end.dateTime || ev.end.date)) || null,
  attendees: (ev.attendees || []).map(a => a.email).filter(e => e && e !== myEmail).slice(0, 8),
  organizer: (ev.organizer || {}).email || null,
  description_excerpt: (ev.description || '').slice(0, 200),
  location: ev.location || null,
  hangout: !!ev.hangoutLink,
}));

const cal_yesterday = [];
const cal_today = [];
for (const ev of calItems) {
  if (!ev.start) continue;
  const dayPT = new Intl.DateTimeFormat('en-CA', { timeZone: 'America/Los_Angeles', year: 'numeric', month: '2-digit', day: '2-digit' }).format(new Date(ev.start));
  if (dayPT === dates.today_pt) cal_today.push(ev);
  else cal_yesterday.push(ev);
}

// --- Sanitize Gmail sent ---
const gmail_summary = { sent_count: (gmail.messages || []).length, error: gmail.error || null };

// --- Sanitize Slack (from Sales User) ---
const slack_matches = ((slack.messages && slack.messages.matches) || []).filter(m => (m.text || '').length >= 25).slice(0, 30).map(m => ({
  channel: (m.channel && (m.channel.name || m.channel.id)) || 'unknown',
  ts_iso: new Date(parseFloat(m.ts) * 1000).toISOString(),
  text: (m.text || '').slice(0, 400),
  permalink: m.permalink,
}));
const slack_summary = { ok: !!slack.ok, count: slack_matches.length, messages: slack_matches, error: slack.error || null };

// --- Sanitize Open Tasks ---
function propText(p) {
  if (!p) return '';
  if (p.title) return p.title.map(t => t.plain_text || '').join('');
  if (p.rich_text) return p.rich_text.map(t => t.plain_text || '').join('');
  if (p.status) return p.status.name || '';
  if (p.select) return (p.select && p.select.name) || '';
  if (p.date) return (p.date && p.date.start) || '';
  return '';
}
const tasks = (openTasks.results || []).slice(0, 50).map(page => {
  const p = page.properties || {};
  return {
    task: propText(p.Task),
    status: propText(p.Status),
    project: propText(p.Project),
    source: propText(p.Source).slice(0, 150),
    notes: propText(p.Notes).slice(0, 500),
    last_edited: page.last_edited_time,
    url: page.url,
  };
}).filter(t => t.task);

const payload = {
  yesterday_long: dates.yesterday_long,
  today_long: dates.today_long,
  yesterday_pt: dates.yesterday_pt,
  today_pt: dates.today_pt,
  meetings: meetings_clean,
  calendar_yesterday: cal_yesterday,
  calendar_today: cal_today,
  gmail_summary,
  slack_summary,
  open_tasks: tasks,
};

const systemPrompt = `You are drafting Sales User's daily standup. Sales User is a sales operator at Example Company.

OUTPUT FORMAT (Slack mrkdwn) - return ONLY the standup text, no preamble, no lead-in:

_Daily Standup - <Today weekday, Month DD>_

_Yesterday_
- <bullet>

_Today_
- <bullet>

_Needs / Blockers_
- <bullet, or 'None at the moment'>

SOURCE PROVENANCE - HARD RULE (read this first):
Every bullet you write MUST be directly traceable to a specific item in the source payload (a meetings record, a calendar event, a slack message, or an open_tasks row). Before writing any bullet, identify which exact source supports it.

If you cannot point to a specific source field that supports the bullet, OMIT the bullet. No exceptions.

DO NOT:
- Infer assessments not stated in the source (e.g. 'X is a better fit', 'Y is unclear') unless that exact framing appears in a source field.
- Generalize across multiple ambiguous signals (e.g. 'notable outreach burst', 'multiple advancing threads').
- Add explanatory framing (e.g. 'for site selection platform pitch', 'as a commissioning acquisition target') unless that exact framing appears in a source field.
- Restate next-step language unless the source data explicitly contains it.

If a source item is ambiguous (e.g., open_tasks row with vague text), either drop it or quote it nearly verbatim. Do not interpret.

When in doubt: OMIT. A shorter, fully-grounded standup is always better than a longer one with invented framing.

FORMATTING RULES:
- Italic section headers via Slack underscores: _Yesterday_, _Today_, _Needs / Blockers_
- Title line uses hyphen: _Daily Standup - Friday, May 15_ (use TODAY's weekday + date)
- Bullet character is '-'. Max 20 words per bullet.
- Group order within each section: external meetings first, then outreach, then internal sessions, then workstream progress.
- Company / individual bullets: 'Company Name (Individual Name): topic or note'
  Example: 'Example Company (External Contact): happy hour; surfaced SFO procurement intel'
  Multiple people: 'Example Prospect (External Contact A / External Contact B): 10am PT call'
- Sub-bullets indented with a hyphen for follow-ons.
- NO em dashes anywhere. No double-hyphen --. Use single hyphen - or comma.
- NO emojis. NO filler / preamble.

SPELLING - DO NOT MISSPELL:
- Executive Stakeholder (NOT 'Executive Ready', NOT 'Executive Reddi')
- Example Company (use the configured company spelling)
- Example Subsidiary (one word)
- Example Business Unit, ExecutiveCo, Example Prospect, Example Contractor, Example Development
- When unsure of a person's name, omit the name rather than guess.

CONTENT RULES:

KEEP IN: external meetings with named counterparties + outcome, outreach Sales User initiated to a named recipient, workstream progress (decks, white papers, n8n builds, target research), scheduling wins with named targets, conferences, internal strategy sessions with named participants + tangible outcome.

KEEP OUT:
- Personal items (ballet, school pickups, family)
- Internal admin (IT, office access) unless it directly unblocks work
- Meetings Sales User declined
- Generic 'reviewed doc' without named-counterparty outcome
- Vague volume claims like 'sent N emails', 'multiple calls today', 'notable outreach burst' - NEVER include email or message counts. Either name the recipient and outcome, or drop the bullet entirely.
- Executive-voice hype language ('excited to', 'great call with', 'aligned on', 'spearheaded')
- Past-tense scheduling items already done or already past (do not bullet 'Reschedule X meeting' if that meeting was yesterday)

NEEDS / BLOCKERS - STRICT DEFINITION:
A 'need' or 'blocker' is something Sales User needs HELP to accomplish, meaning ONE of:
(a) Someone else owes Sales User something specific (a response, a decision, an intro, access, sign-off), OR
(b) Sales User is stuck on something and needs a teammate's input to unstick.

DO NOT include in Needs / Blockers:
- Action items Sales User owns and can do himself ('send X', 'draft Y', 'advance Z', 'follow up with W') - these belong in 'Today', not in 'Needs / Blockers'.
- Items that are simply next-steps in Sales User's own queue.
- Past items already resolved or no longer relevant.
- Items where you cannot identify a specific named person Sales User is waiting on AND specifically what they owe.
- Items you cannot verify from the source data - DO NOT fabricate or interpret loosely. If unsure, leave out.

PREFER 'None at the moment' over fabricating Needs/Blockers. A real blocker has: (a) a named person who owes Sales User something specific, AND (b) clear evidence in the source data (an open tasks row with explicit 'awaiting X', 'pending from Y', 'blocked by Z', 'need X to do Y' language). Generic ambiguous open tasks rows are NOT blockers.

VOICE: first-person operator. Plain verbs (met with, scoped, locked, pushed, sent). No positioning verbs (spearheaded, drove alignment on, championed). No throat-clearing or hedges.

DATA SOURCES PROVIDED:
- meetings: federated query across two Notion meeting DBs. 'pairs' = same meeting captured by both; 'CRM_only' = calendar/Notetaker only; 'recall_only' = in-person/HiDock only. Use for 'Yesterday' meeting bullets.
- calendar_yesterday / calendar_today: filtered Google Calendar events. Use calendar_today for 'Today' meeting bullets. Use calendar_yesterday only as backup if a meeting doesn't appear in 'meetings'.
- gmail_summary: provides only a count. DO NOT bullet email volume. Skip this field entirely unless you can name a specific recipient and outcome from elsewhere in the data.
- slack_summary: Sales User's outbound Slack from yesterday. Use to surface external-facing pushes or commitments Sales User made.
- open_tasks: Example Company Open Tasks DB rows where Status != Done. Use for 'Today' (items Sales User owes/will work on) and for 'Needs / Blockers' (ONLY if the row text explicitly indicates Sales User is waiting on a named someone else). When in doubt, treat as Sales User's own action items for 'Today', not as blockers.

IF DATA IS MISSING for a source (error field present, or empty), note it inline at the BOTTOM of the relevant section as a single italicized line: '_(meetings data unavailable)_'. Continue with what you have.

Return ONLY the standup text, ready to post to Slack. No JSON, no markdown code fences, no commentary, no lead-in.`;

const userPrompt = `Source data for ${dates.today_long}:\n\n${JSON.stringify(payload, null, 2)}`;

return { payload, systemPrompt, userPrompt, dates };

const llm = $input.first().json || {};
const dates = $('Bundle + build prompt').first().json.dates;

let draftText = '';
let llmError = null;
try {
  draftText = ((llm.content || []).map(c => c.text || '').join('') || '').trim();
  draftText = draftText.replace(/^```[a-zA-Z]*\n?/, '').replace(/\n?```\s*$/, '').trim();
  if (!draftText) throw new Error('empty draft from Anthropic');
} catch (e) {
  llmError = e.message;
  draftText = `_Daily Standup - ${dates.today_long}_\n\n_Yesterday_\n- (LLM synthesis failed: ${llmError}. Manual draft required.)\n\n_Today_\n- (see calendar)\n\n_Needs / Blockers_\n- None at the moment`;
}

const slackText = draftText;

return { draftText, slackText, llmError, dates };

const draft = $('Parse draft').first().json;
const slackResp = $input.first().json || {};

const posted_ts = slackResp.ts || (slackResp.message && slackResp.message.ts) || null;
const slack_ok = !!(slackResp.ok && posted_ts);
const slack_error = slack_ok ? null : (slackResp.error || JSON.stringify(slackResp).slice(0, 500));

let fallback_needed = !slack_ok;
let fallback_payload = null;
if (fallback_needed) {
  const subject = `[STANDUP FALLBACK ${draft.dates.today_pt}]`;
  const body = `Slack post failed after 3 retries. Draft below.\n\n${draft.draftText}\n\n---\nError details: ${slack_error}`;
  const raw = [
    `To: sales.user@example.com`,
    `From: sales.user@example.com`,
    `Subject: ${subject}`,
    `Content-Type: text/plain; charset=UTF-8`,
    ``,
    body,
  ].join('\r\n');
  const b64 = Buffer.from(raw, 'utf-8').toString('base64').replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '');
  fallback_payload = { message: { raw: b64 } };
}

return {
  slack_ok,
  posted_ts,
  slack_error,
  fallback_needed,
  fallback_payload,
  draft_text: draft.draftText,
  llm_error: draft.llmError,
  dates: draft.dates,
};

const verify = $('Verify + plan fallback').first().json;
const draftSummary = {
  date: verify.dates.today_pt,
  slack_ok: verify.slack_ok,
  slack_ts: verify.posted_ts,
  slack_error: verify.slack_error,
  llm_error: verify.llm_error,
  fallback_needed: verify.fallback_needed,
  draft_preview: (verify.draft_text || '').slice(0, 2000),
  generated_at: new Date().toISOString(),
};
let fallback_result = null;
try {
  const fb = $('Create Gmail fallback draft').first();
  if (fb && fb.json) fallback_result = { draft_id: fb.json.id, message_id: (fb.json.message || {}).id };
} catch (e) {}
return { ...draftSummary, fallback_result };
